import{_ as o,o as t,c as n,ag as s}from"./chunks/framework.6ZJjlmu_.js";const h=JSON.parse('{"title":"ILPP vs ReflectionScanner","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/ilpp-vs-reflection-scanner.md","filePath":"concepts/ilpp-vs-reflection-scanner.md"}'),r={name:"concepts/ilpp-vs-reflection-scanner.md"};function i(a,e,l,c,d,p){return t(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="ilpp-vs-reflectionscanner" tabindex="-1">ILPP vs ReflectionScanner <a class="header-anchor" href="#ilpp-vs-reflectionscanner" aria-label="Permalink to &quot;ILPP vs ReflectionScanner&quot;">​</a></h1><p>Event Monitor can observe subscriptions from two mechanisms. They complement each other but behave differently.</p><h2 id="il-post-processor-ilpp" tabindex="-1">IL Post-Processor (ILPP) <a class="header-anchor" href="#il-post-processor-ilpp" aria-label="Permalink to &quot;IL Post-Processor (ILPP)&quot;">​</a></h2><p>After compilation, Event Monitor’s <strong>ILPP</strong> rewrites eligible assemblies to inject calls at:</p><ul><li>Event <strong>add</strong> accessors (<code>+=</code>)</li><li>Event <strong>remove</strong> accessors (<code>-=</code>)</li><li>Common <strong>invocation</strong> sites (see <a href="./../reference/il-limitations.html">IL patterns and limitations</a>)</li></ul><p><strong>Pros</strong></p><ul><li>Precise <strong>compile-time</strong> placement: every instrumented <code>+=</code> / <code>-=</code> / <code>Invoke</code> is tied to real IL sites.</li><li><strong>INVOKE</strong> rows (when the pattern matches) without polling.</li></ul><p><strong>Cons</strong></p><ul><li>Only assemblies and patterns the processor <strong>understands</strong> are covered.</li><li>Requires a successful ILPP pass and compatible Unity / Cecil setup.</li></ul><h2 id="reflectionscanner" tabindex="-1">ReflectionScanner <a class="header-anchor" href="#reflectionscanner" aria-label="Permalink to &quot;ReflectionScanner&quot;">​</a></h2><p><code>ReflectionScanner</code> is a <strong>runtime</strong> <code>MonoBehaviour</code> that periodically scans <code>MonoBehaviour</code> instances in the scene, reflects over <strong>delegate fields</strong>, and diffs handler sets to emit <strong>SUB</strong> / <strong>UNSUB</strong> records.</p><p><strong>Pros</strong></p><ul><li>Useful when ILPP is <strong>off</strong>, <strong>skipped</strong>, or not applied to a particular assembly.</li><li>Can surface subscription changes discovered purely by reflection.</li></ul><p><strong>Cons</strong></p><ul><li><strong>Polling</strong> — work every <em>N</em> frames; potential overhead on large scenes.</li><li>Less precise than ILPP for attribution; may disagree slightly with ILPP timing.</li><li>Does <strong>not</strong> replace <strong>INVOKE</strong> injection; invocation still depends on ILPP (or manual hooks).</li></ul><h2 id="using-both" tabindex="-1">Using both <a class="header-anchor" href="#using-both" aria-label="Permalink to &quot;Using both&quot;">​</a></h2><p>When ILPP subscription instrumentation <strong>and</strong> ReflectionScanner are active, you may see <strong>additional</strong> SUB/UNSUB activity compared to ILPP alone, because both paths can record the same logical change.</p><p>For a clean mental model:</p><ul><li>Prefer <strong>ILPP</strong> for production debugging of the full <strong>SUB / UNSUB / INVOKE</strong> story.</li><li>Treat <strong>ReflectionScanner</strong> as a <strong>fallback</strong> or demo aid (the generated demo scene includes it intentionally).</li></ul><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./../how-to/ilpp-diagnostics.html">ILPP diagnostics and settings</a></li><li><a href="./../reference/il-limitations.html">IL patterns and limitations</a></li></ul>',21)])])}const u=o(r,[["render",i]]);export{h as __pageData,u as default};
